function Login({ onLogin }) {
  const [sel, setSel] = useState("trainee");
  const me = ROLES[sel];
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");

  async function handleLogin() {
    if (busy) return;
    setErr("");
    if (!email || !password) { setErr("メールアドレスとパスワードを入力してください。"); return; }
    setBusy(true);
    try {
      try { await signOut(); } catch (e) {}
      const { isSignedIn, nextStep } = await signIn({ username: email.trim(), password });
      if (isSignedIn || nextStep?.signInStep === "DONE") {
        onLogin(sel);
      } else if (nextStep?.signInStep === "CONFIRM_SIGN_IN_WITH_NEW_PASSWORD_REQUIRED") {
        setErr("初回ログインのためパスワード変更が必要です。管理者側で確定パスワードを設定してから再度お試しください。");
      } else if (nextStep?.signInStep === "CONFIRM_SIGN_UP") {
        setErr("メールアドレスの確認が未完了です。確認コードでの認証が必要です。");
      } else {
        setErr("追加の認証ステップが必要です：" + (nextStep?.signInStep || "不明"));
      }
    } catch (e) {
      const n = e?.name || "";
      if (n === "UserNotFoundException" || n === "NotAuthorizedException") setErr("メールアドレスまたはパスワードが正しくありません。");
      else if (n === "UserNotConfirmedException") setErr("メールアドレスの確認が未完了です。");
      else setErr(e?.message || "ログインに失敗しました。");
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="grid min-h-screen lg:grid-cols-2" style={{ background: C.canvas, fontFamily: "'Inter','Noto Sans JP',sans-serif" }}>
      {/* ブランドパネル */}
      <div className="relative hidden flex-col justify-between overflow-hidden p-12 text-white lg:flex" style={{ background: GRAD2 }}>
        <div className="absolute inset-0" style={{ backgroundImage: DOTS }} />
        <div className="pointer-events-none absolute -right-20 -top-20 h-72 w-72 rounded-full" style={{ background: "rgba(255,255,255,.08)" }} />
        <div className="pointer-events-none absolute -bottom-24 -left-16 h-80 w-80 rounded-full" style={{ background: "rgba(255,255,255,.06)" }} />
        <div className="relative">
          <div className="inline-flex items-center gap-2 rounded-xl bg-white px-3 py-2">
            <img src={LOGO} alt="Feeps" style={{ height: 24 }} />
            <span className="text-xs font-bold" style={{ color: C.muted }}>研修管理</span>
          </div>
        </div>
        <div className="relative flex flex-col items-center text-center">
          <div className="rounded-3xl bg-white p-6" style={{ boxShadow: "0 20px 50px rgba(0,0,0,.18)" }}>
            <img src={ILLUS.study} alt="" style={{ width: 300, maxWidth: "100%" }} />
          </div>
          <h1 className="mt-6 text-2xl font-bold leading-snug">学びを、成長へ。</h1>
          <p className="mt-2 max-w-xs text-sm opacity-90">受講・指導・管理をひとつに。Feepsの研修をもっと効果的に、もっと実践的に。</p>
        </div>
        <div className="relative text-xs opacity-80">Fun, Effective, Efficient, Practical for Sharing Special Smiles</div>
      </div>

      {/* フォーム */}
      <div className="flex items-center justify-center p-6 sm:p-12">
        <div className="w-full max-w-sm">
          <div className="mb-8 flex items-center gap-2 lg:hidden">
            <img src={LOGO} alt="Feeps" style={{ height: 26 }} /><span className="text-xs font-bold" style={{ color: C.muted }}>研修管理</span>
          </div>
          <h2 className="text-2xl font-bold" style={{ color: C.ink }}>ログイン</h2>
          <p className="mt-1 text-sm" style={{ color: C.muted }}>アカウント情報を入力してください</p>

          <div className="mt-6 space-y-3">
            <div className="flex items-center gap-2 rounded-xl px-3" style={{ border: `1px solid ${C.line2}`, background: "#fff" }}>
              <Mail size={16} style={{ color: C.muted }} />
              <input value={email} onChange={e => setEmail(e.target.value)} placeholder={me.mail} type="email" autoComplete="username" className="w-full bg-transparent py-3 text-sm outline-none" style={{ color: C.ink }} />
            </div>
            <div className="flex items-center gap-2 rounded-xl px-3" style={{ border: `1px solid ${C.line2}`, background: "#fff" }}>
              <Lock size={16} style={{ color: C.muted }} />
              <input type="password" value={password} onChange={e => setPassword(e.target.value)} onKeyDown={e => { if (e.key === "Enter") handleLogin(); }} placeholder="パスワード" autoComplete="current-password" className="w-full bg-transparent py-3 text-sm outline-none" style={{ color: C.ink }} />
            </div>
            <div className="flex items-center justify-between text-xs" style={{ color: C.muted }}>
              <label className="flex items-center gap-1.5"><input type="checkbox" defaultChecked /> ログイン状態を保持</label>
              <span style={{ color: C.cyanDeep }}>パスワードを忘れた方</span>
            </div>
            {err && <div className="rounded-lg px-3 py-2 text-xs" style={{ background: "#FCEAEF", color: "#C8385F" }}>{err}</div>}
            <Btn kind="grad" full size="lg" icon={LogIn} onClick={handleLogin}>{busy ? "ログイン中…" : "ログイン"}</Btn>
          </div>

          <div className="mt-7">
            <div className="mb-2 text-xs font-semibold" style={{ color: C.muted }}>表示するロールを選択（暫定・今後Cognito連携に置換）</div>
            <div className="grid grid-cols-2 gap-2">
              {Object.values(ROLES).map(r => {
                const active = sel === r.key;
                return <button key={r.key} onClick={() => setSel(r.key)}
                  className="flex items-center gap-2 rounded-xl px-3 py-2.5 text-sm font-semibold transition"
                  style={{ border: `1.5px solid ${active ? C.cyan : C.line2}`, background: active ? C.wash : "#fff", color: active ? C.cyanDeep : C.body }}>
                  <r.icon size={15} />{r.label}</button>;
              })}
            </div>
          </div>
          <div className="mt-8 text-center text-xs" style={{ color: C.faint }}>{FOOTER}</div>
        </div>
      </div>
    </div>
  );
}

