function engToSheet(e) {
  const skills = Object.entries(e.skills).map(([name, level]) => ({ cat: SKILL_CAT[name] || "その他", name, level }));
  return { p: { name: e.name, age: e.age, station: e.station, title: e.title, exp: e.exp },
    selfPR: buildSelfPR({ title: e.title, exp: e.exp }, e.strengths || [], e.weak || [], skills, e.projects || []),
    strengths: e.strengths || [], weak: e.weak || [], skills, projects: e.projects || [] };
}
function matchOf(e, o) {
  let sum = 0; const matched = [], missing = [];
  o.req.forEach(r => { const lv = e.skills[r.skill] || 0; sum += Math.min(lv / r.level, 1); (lv >= r.level ? matched : missing).push(r.skill); });
  return { score: Math.round((sum / o.req.length) * 100), matched, missing };
}
function matchTone(s) { return s >= 80 ? "green" : s >= 60 ? "cyan" : s >= 40 ? "amber" : "muted"; }
function ProjectMatching() {
  const [oid, setOid] = useState(OPENINGS[0].id);
  const [assign, setAssign] = useState({});
  const [preview, setPreview] = useState(null);
  const o = OPENINGS.find(x => x.id === oid);
  const ranked = ENGINEERS.map(e => ({ e, ...matchOf(e, o) })).sort((a, b) => b.score - a.score);
  const assigned = assign[oid] || [];
  function toggleAssign(eid) { setAssign(s => { const cur = s[oid] || []; return { ...s, [oid]: cur.includes(eid) ? cur.filter(x => x !== eid) : [...cur, eid] }; }); }
  if (preview) return (
    <div>
      <div className="mb-4"><Btn kind="ghost" size="sm" icon={ChevronLeft} onClick={() => setPreview(null)}>案件選定に戻る</Btn></div>
      <SkillSheetPreview data={engToSheet(preview)} onClose={() => setPreview(null)} />
    </div>
  );
  return (
    <div>
      <SectionHead title="案件アサイン" desc="社員のスキルシートから、案件にマッチする人材を選定します" />
      <div className="-mx-1 mb-5 flex gap-3 overflow-x-auto px-1 pb-1">
        {OPENINGS.map(op => { const a = (assign[op.id] || []).length; const active = op.id === oid;
          return (
            <button key={op.id} onClick={() => setOid(op.id)} className="w-64 shrink-0 rounded-2xl p-4 text-left transition"
              style={{ background: active ? C.wash : "#fff", border: `1.5px solid ${active ? C.cyan : C.line2}` }}>
              <div className="flex items-center justify-between"><Badge tone="cyan">{op.industry}</Badge>
                <span className="text-xs font-semibold" style={{ color: a >= op.headcount ? C.green : C.muted }}>{a}/{op.headcount}名</span></div>
              <div className="mt-2 text-sm font-bold leading-snug" style={{ color: C.ink }}>{op.name}</div>
              <div className="mt-1 text-xs" style={{ color: C.muted }}>{op.company} ・ {op.period}</div>
              <div className="mt-2 flex flex-wrap gap-1">{op.req.map(r => <span key={r.skill} className="rounded px-1.5 py-0.5 text-xs font-semibold" style={{ background: C.canvas, color: C.body }}>{r.skill}</span>)}</div>
            </button>
          );
        })}
      </div>

      <Card className="mb-5 p-5">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div><h3 className="font-bold" style={{ color: C.ink }}>{o.name}</h3>
            <div className="mt-1 flex flex-wrap gap-x-4 gap-y-1 text-xs" style={{ color: C.muted }}>
              <span className="inline-flex items-center gap-1"><Building2 size={12} />{o.company}</span>
              <span className="inline-flex items-center gap-1"><Calendar size={12} />{o.period}</span>
              <span className="inline-flex items-center gap-1"><MapPin size={12} />{o.location}</span>
              <span>単価 {o.rate}</span><span>募集 {o.headcount}名</span></div></div>
        </div>
        <div className="mt-3 flex flex-wrap items-center gap-2">
          <span className="text-xs font-bold" style={{ color: C.muted }}>必要スキル：</span>
          {o.req.map(r => <span key={r.skill} className="rounded-full px-2.5 py-1 text-xs font-semibold" style={{ background: C.wash, color: C.cyanDeep }}>{r.skill}（{r.level}+）</span>)}
          <span className="text-xs font-bold" style={{ color: C.muted }}>｜ 工程：</span>
          {o.phases.map(ph => <span key={ph} className="rounded px-1.5 py-0.5 text-xs font-semibold" style={{ background: C.greenW, color: C.green }}>{ph}</span>)}
        </div>
      </Card>

      <div className="space-y-3">{ranked.map(({ e, score, matched, missing }, i) => { const isA = assigned.includes(e.id);
        return (
          <Card key={e.id} className="p-4" style={i === 0 ? { border: `1.5px solid ${C.cyan}` } : undefined}>
            <div className="flex flex-wrap items-center gap-3">
              <Avatar name={e.name} size={42} />
              <div className="min-w-0 flex-1">
                <div className="flex flex-wrap items-center gap-2"><span className="text-sm font-bold" style={{ color: C.ink }}>{e.name}</span>
                  {i === 0 && <Badge tone="cyan">最適</Badge>}{isA && <Badge tone="green">アサイン済</Badge>}</div>
                <div className="text-xs" style={{ color: C.muted }}>{e.title} ・ {e.exp} ・ 稼働 {e.avail}</div>
              </div>
              <div className="w-24 text-right">
                <div className="text-lg font-bold" style={{ color: score >= 80 ? C.green : score >= 60 ? C.cyanDeep : score >= 40 ? C.amber : C.muted }}>{score}%</div>
                <div className="text-xs" style={{ color: C.faint }}>マッチ度</div>
              </div>
            </div>
            <div className="mt-2"><Bar value={score} tone={matchTone(score)} /></div>
            <div className="mt-2 flex flex-wrap gap-1.5">
              {matched.map(s => <span key={s} className="inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-xs font-semibold" style={{ background: C.greenW, color: C.green }}><CheckCircle2 size={11} />{s}</span>)}
              {missing.map(s => <span key={s} className="inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-xs font-semibold" style={{ background: C.amberW, color: C.amber }}><AlertCircle size={11} />{s} 不足</span>)}
            </div>
            <div className="mt-3 flex justify-end gap-2">
              <Btn kind="ghost" size="sm" icon={FileText} onClick={() => setPreview(e)}>スキルシート</Btn>
              <Btn kind={isA ? "soft" : "primary"} size="sm" icon={isA ? X : Plus} onClick={() => toggleAssign(e.id)}>{isA ? "アサイン解除" : "この案件にアサイン"}</Btn>
            </div>
          </Card>
        );
      })}</div>
      <p className="mt-3 text-xs" style={{ color: C.faint }}>※ マッチ度は各社員の保有スキルと案件の必要スキル・レベルから算出（デモ）。不足スキルはEラーニングでの補強候補になります。</p>
    </div>
  );
}

