function riskLevel(s) { return s >= 60 ? { k: "高", tone: "red", col: C.red } : s >= 35 ? { k: "中", tone: "amber", col: C.amber } : { k: "低", tone: "green", col: C.green }; }
const RISK_SIG_LABEL = { 日報: "日報の傾向", テスト: "テスト推移", 勤怠: "勤怠（遅刻・欠席）", 学習時間: "学習時間" };
function RiskBoard() {
  const sorted = [...RISK].sort((a, b) => b.score - a.score);
  const [open, setOpen] = useState(sorted[0]?.name ?? null);
  const hi = RISK.filter(r => r.score >= 60).length;
  const mid = RISK.filter(r => r.score >= 35 && r.score < 60).length;
  const lo = RISK.length - hi - mid;
  return (
    <div>
      <SectionHead title="リスク分析" desc="日報・テスト・勤怠・学習時間からAIが離脱／つまずきリスクを推定します（デモ）" />
      <div className="mb-5 grid gap-4 sm:grid-cols-3">
        <Stat icon={AlertCircle} label="高リスク" value={`${hi}名`} tone="amber" />
        <Stat icon={Activity} label="中リスク" value={`${mid}名`} tone="cyan" />
        <Stat icon={ShieldCheck} label="低リスク" value={`${lo}名`} tone="green" />
      </div>
      <Card>
        {sorted.map((r, i) => { const lv = riskLevel(r.score); const isOpen = open === r.name;
          return (
            <div key={r.name} style={{ borderTop: i ? `1px solid ${C.line}` : "none" }}>
              <button onClick={() => setOpen(isOpen ? null : r.name)} className="flex w-full items-center gap-3 px-4 py-3.5 text-left">
                <Avatar name={r.name} size={36} />
                <div className="min-w-0 flex-1">
                  <div className="flex items-center gap-2"><span className="text-sm font-bold" style={{ color: C.ink }}>{r.name}</span><span className="hidden text-xs sm:inline" style={{ color: C.muted }}>{r.org}</span></div>
                  <div className="truncate text-xs" style={{ color: C.muted }}>主因：{r.top}</div></div>
                <div className="hidden w-32 md:block"><Bar value={r.score} tone={lv.k === "低" ? "green" : "amber"} /></div>
                <Badge tone={lv.tone}>{lv.k}リスク {r.score}</Badge>
                <ChevronRight size={16} style={{ color: C.muted, transform: isOpen ? "rotate(90deg)" : "none", transition: "transform .2s" }} />
              </button>
              {isOpen && (
                <div className="px-4 pb-4">
                  <div className="grid gap-2 sm:grid-cols-2">{Object.entries(r.signals).map(([k, v]) => (
                    <div key={k} className="rounded-xl p-3" style={{ background: C.canvas }}>
                      <div className="mb-1 flex justify-between text-xs"><span style={{ color: C.body }}>{RISK_SIG_LABEL[k]}</span>
                        <span style={{ color: v >= 60 ? C.red : v >= 35 ? C.amber : C.green }}>懸念 {v}</span></div>
                      <Bar value={v} tone={v >= 35 ? "amber" : "green"} /></div>
                  ))}</div>
                  <div className="mt-3 flex items-start gap-2 rounded-xl p-3.5" style={{ background: C.wash, border: `1px solid ${C.washDeep}` }}>
                    <Sparkles size={16} style={{ color: C.cyanDeep, marginTop: 2 }} />
                    <div><div className="text-xs font-bold" style={{ color: C.cyanDeep }}>AIによる改善提案</div>
                      <div className="mt-0.5 text-sm leading-relaxed" style={{ color: C.ink }}>{r.advice}</div></div>
                  </div>
                  <div className="mt-3 flex justify-end gap-2"><Btn kind="ghost" size="sm">面談を設定</Btn><Btn size="sm" icon={Send}>講師へ共有</Btn></div>
                </div>
              )}
            </div>
          );
        })}
      </Card>
      <p className="mt-3 text-xs" style={{ color: C.faint }}>※ 本画面はデモ用のサンプル分析です。実運用では日報・テスト・勤怠・学習時間の実データをもとに算出します。</p>
    </div>
  );
}

